# ops/deploy_gate.py
# Block non-critical deploys when error budget is below threshold.
from dataclasses import dataclass
from typing import List
import requests

PROMETHEUS = 'http://prometheus:9090'

@dataclass
class BudgetStatus:
    slo_name: str
    budget_remaining_pct: float  # 0-100
    burn_rate: float

DEPLOY_GATE_THRESHOLDS = {
    'soft_freeze': 20.0,   # warn engineers, require approval
    'hard_freeze': 5.0,    # block all non-emergency deploys
}

def query(q: str) -> float:
    r = requests.get(f'{PROMETHEUS}/api/v1/query',
                     params={'query': q}, timeout=5)
    result = r.json()['data']['result']
    return float(result[0]['value'][1]) if result else float('nan')

def get_budget_statuses() -> List[BudgetStatus]:
    avail_error_rate = 1 - query('sli:availability:ratio_1h')
    avail_budget = 1 - 0.999
    avail_consumed = avail_error_rate / avail_budget if avail_budget else 0

    eval_rate = query('sli:eval_pass_rate:avg_7d')
    eval_budget = 1 - 0.94  # 6pp
    eval_consumed = max(0, (0.94 - eval_rate) / eval_budget) if eval_budget else 0

    return [
        BudgetStatus('availability',
                     (1 - avail_consumed) * 100,
                     avail_error_rate / avail_budget if avail_budget else 0),
        BudgetStatus('eval_pass_rate',
                     (1 - eval_consumed) * 100,
                     max(0, (0.94 - eval_rate) / eval_budget) * 30 if eval_budget else 0),
    ]

def check_deploy_allowed(is_emergency: bool = False) -> dict:
    if is_emergency:
        return {'allowed': True, 'reason': 'Emergency deploy always allowed'}
    statuses = get_budget_statuses()
    critical = [s for s in statuses
                if s.budget_remaining_pct < DEPLOY_GATE_THRESHOLDS['hard_freeze']]
    warnings = [s for s in statuses
                if s.budget_remaining_pct < DEPLOY_GATE_THRESHOLDS['soft_freeze']]
    if critical:
        names = [s.slo_name for s in critical]
        return {
            'allowed': False,
            'reason': f'Hard freeze: {names} budget below 5%',
        }
    if warnings:
        names = [s.slo_name for s in warnings]
        return {
            'allowed': True,
            'warning': f'Soft freeze: {names} budget below 20% — approval required',
        }
    return {'allowed': True, 'reason': 'Budget healthy'}

if __name__ == '__main__':
    result = check_deploy_allowed()
    print(result)
